import React from 'react'
import { useState, useEffect } from "react";
import PropTypes from 'prop-types'
import { Nav, Navbar, Container, NavbarBrand } from 'react-bootstrap'
import navIcon1 from '../assets/img/nav-icon1.svg';
import navIcon2 from '../assets/img/nav-icon2.svg';
import navIcon3 from '../assets/img/nav-icon3.svg';
import { BrowserRouter as Router } from "react-router-dom";
// import { HashLink } from 'react-router-hash-link';

export default function NavBar(props) {

  const [activeLink, setActiveLink] = useState('home');
  const [scrolled , setScrolled] = useState(false);

  useEffect(()=>{
    const onScroll = ()=>{
      if(window.scrollY>50){
        setScrolled(true);
      }else{
        setScrolled(false);
      }
    }
  })
  const onUpdateActiveLink = (value) => {
    setActiveLink(value);
  }
  return (
    <>
      <Router>
        <Navbar className={scrolled ? "scrolled" : ""}>
          <Container>
            {/* <Navbar.Brand href="/">
            
          </Navbar.Brand> */}
            <Nav.Link className="navbar-brand mx-3 fw-bold text-white" href="/">{props.title}</Nav.Link>
            <Navbar.Toggle aria-controls="basic-navbar-nav" aria-expanded="false" aria-label="Toggle navigation">
              <span className="navbar-toggler-icon"></span>
            </Navbar.Toggle>
            <Nav className="ms-auto">
              <Nav.Link href="#home" className={activeLink === 'home' ? 'active navbar-link' : 'navbar-link'} onClick={() => onUpdateActiveLink('home')}>Home</Nav.Link>
              <Nav.Link href="#getintouch" className={activeLink === 'getintouch' ? 'active navbar-link' : 'navbar-link'} onClick={() => onUpdateActiveLink('getintouch')} >{props.getintouch}</Nav.Link>
              <Nav.Link href="#about" className={activeLink === 'about' ? 'active navbar-link' : 'navbar-link'} onClick={() => onUpdateActiveLink('about')}>{props.aboutText}</Nav.Link>
            </Nav>
            <span className="navbar-text">
              <div className="social-icon">
                <a href="#"><img src={navIcon1} alt="" /></a>
                <a href="#"><img src={navIcon2} alt="" /></a>
                <a href="#"><img src={navIcon3} alt="" /></a>
              </div>
              {/* <HashLink to='#connect'>
                    <button className="vvd"><span>Let's Connect</span></button>
                  </HashLink> */}
            </span>
          </Container>
        </Navbar>
      </Router>
    </>

  )
}

NavBar.prototype = {
  title: PropTypes.string.isRequired,
  videos: PropTypes.string.isRequired
}

NavBar.defaultProps = {
  title: "Alan.is",
  getintouch: "Get in Touch",
  aboutText: "About me"
};
